import { pipe } from "fp-ts/function";

interface Lens<S, A> {
  readonly get: (s: S) => A;
  readonly set: (a: A) => (s: S) => S;
}

const lens = <S, A>(get: (s: S) => A, set: (a: A) => (s: S) => S): Lens<S, A> => ({ get, set });

const compose = <S, A, B>(outer: Lens<S, A>, inner: Lens<A, B>): Lens<S, B> =>
  lens(
    (s) => inner.get(outer.get(s)),
    (b) => (s) => outer.set(inner.set(b)(outer.get(s)))(s),
  );

interface Address { readonly city: string; readonly zip: string }
interface User { readonly name: string; readonly address: Address }

const addressL: Lens<User, Address> = lens(
  (u) => u.address,
  (a) => (u) => ({ ...u, address: a }),
);
const cityL: Lens<Address, string> = lens(
  (a) => a.city,
  (c) => (a) => ({ ...a, city: c }),
);
const userCityL: Lens<User, string> = compose(addressL, cityL);

const u: User = { name: "Ada", address: { city: "London", zip: "N1" } };
export const updated = pipe(u, userCityL.set("Paris"));
