A `Lens<S, A>` bundles a `get` and an immutable `set` for a focused part `A` of a whole `S`. Because `set` rebuilds the outer structure, we never mutate — we derive. Composing two lenses gives us a lens on the composed focus; `modify` is `set ∘ f ∘ get`.

```typescript
import { pipe } from "fp-ts/function";

interface Lens<S, A> { readonly get: (s: S) => A; readonly set: (a: A) => (s: S) => S }
const mk = <S, A>(g: (s: S) => A, s: (a: A) => (x: S) => S): Lens<S, A> => ({ get: g, set: s });
const modify = <S, A>(l: Lens<S, A>, f: (a: A) => A) => (s: S) => l.set(f(l.get(s)))(s);

interface Settings { readonly counter: number; readonly flag: boolean }
interface App { readonly settings: Settings }

const settingsL: Lens<App, Settings> = mk((a) => a.settings, (v) => (a) => ({ ...a, settings: v }));
const counterL: Lens<Settings, number> = mk((s) => s.counter, (n) => (s) => ({ ...s, counter: n }));

const app: App = { settings: { counter: 0, flag: false } };
const bump = (a: App) => modify(settingsL, (s) => ({ ...s, counter: counterL.get(s) + 1 }))(a);
export const next = pipe(app, bump, bump);

