A `Lens<S, A>` always finds its focus — total get, total set. An `Optional<S, A>` is partial: `getOption` may return `O.none`, and `set` is a no-op when the focus doesn't exist. Perfect for array heads, optional fields, and tagged-union branches.

```typescript
import { pipe } from "fp-ts/function";
import * as O from "fp-ts/Option";

interface Optional<S, A> {
  readonly getOption: (s: S) => O.Option<A>;
  readonly set: (a: A) => (s: S) => S;
}

const head = <A>(): Optional<ReadonlyArray<A>, A> => ({
  getOption: (xs) => (xs.length > 0 ? O.some(xs[0] as A) : O.none),
  set: (a) => (xs) => (xs.length > 0 ? [a, ...xs.slice(1)] : xs),
});

const first = head<number>();
const xs: ReadonlyArray<number> = [1, 2, 3];
const empty: ReadonlyArray<number> = [];

export const read = pipe(xs, first.getOption, O.getOrElse(() => -1));
export const written = pipe(xs, first.set(99));
export const absent = pipe(empty, first.getOption, O.isNone);

