import * as N from "fp-ts/number";

const byValueDesc: Ord<readonly [string, number]> = pipe(
  N.Ord,
  contramap((p: readonly [string, number]) => p[1]),
  reverse,
);

const rec: Record<string, number> = { a: 1, b: 5, c: 3 };

export const sorted = pipe(
  rec,
  R.toEntries,
  (xs) => A.sort(byValueDesc)(xs),
  R.fromEntries,
);

