import { Effect, Match, pipe } from "effect";

type Click = { readonly _tag: "Click"; readonly x: number; readonly y: number };
type KeyDown = { readonly _tag: "KeyDown"; readonly key: string };
type Focus = { readonly _tag: "Focus"; readonly el: string };
type Event = Click | KeyDown | Focus;

const describe = (e: Event): Effect.Effect<string> =>
  pipe(
    Match.type<Event>(),
    Match.tag("Click", (c) => Effect.succeed(`click@${c.x},${c.y}`)),
    Match.tag("KeyDown", (k) => Effect.succeed(`key:${k.key}`)),
    Match.tag("Focus", (f) => Effect.succeed(`focus:${f.el}`)),
    Match.exhaustive,
  )(e);

export const program = describe({ _tag: "Click", x: 10, y: 20 });

