import { Effect, Match, pipe } from "effect";

type State = { readonly _tag: "Idle" } | { readonly _tag: "Loading" } | { readonly _tag: "Done"; readonly value: number };

const step = (s: State): Effect.Effect<string> =>
  pipe(
    Match.type<State>(),
    Match.tag("Idle", () => Effect.succeed("waiting")),
    Match.tag("Loading", () => Effect.succeed("loading")),
    Match.tag("Done", (d) => Effect.succeed(`done:${d.value}`)),
    Match.exhaustive,
  )(s);

export const p = step({ _tag: "Done", value: 42 });

```

`Match.type<T>()` builds a pattern matcher up front for a *type* and is applied later to any value of that type — ideal for tagged unions. `Match.value(x)` starts with a concrete value and composes branches against it — ideal for one-off dispatches.

