import { Effect, Match, pipe } from "effect";

const statusOf = (age: number): Effect.Effect<string> =>
  pipe(
    Match.value(age),
    Match.when((a) => a < 13, () => Effect.succeed("child")),
    Match.when((a) => a < 20, () => Effect.succeed("teen")),
    Match.when((a) => a < 65, () => Effect.succeed("adult")),
    Match.orElse(() => Effect.succeed("senior")),
  );

