      (s) => Effect.succeed(`string of length ${s.length}`),
    ),
    Match.when(
      (x: unknown): x is number => typeof x === "number",
      (n) => Effect.succeed(`number ${n}`),
    ),
    Match.orElse(() => Effect.succeed("other")),
  );

export const p1 = describe("hi");
