  pipe(
    Match.value(a),
    Match.when(isAdmin, () => Effect.succeed("all")),
    Match.when(isOwner, () => Effect.succeed("write")),
    Match.when(isMember, () => Effect.succeed("read")),
    Match.orElse(() => Effect.succeed("none")),
  );

